%% plot_collected_metrics.m
% =========================================================================
% EMQX Cloud – Collected Broker Metrics Visualization
% =========================================================================
%
% Description:
%   Reads the CSV file generated by collect_metrics.py and produces one
%   figure per metric, replicating the visual style of the EMQX Cloud
%   dashboard (Sessions, Subscriptions, Messages, Packets).
%
%   Each plot includes:
%     - Zero-padded boundaries (curves start and end at 0)
%     - Dual-layer grid (major + minor) with soft transparency
%     - Y-axis label with metric name and unit
%
% Input:
%   <repo>/data/raw/collected_metrics_220tags.csv
%
% Output:
%   One MATLAB figure window per metric (7 total).
%
% Dependencies:
%   MATLAB R2019b or later.
%
% Author:
%   Juliam Diaz – Master's Thesis, 2025
% =========================================================================

%% Path configuration – adjust if repo location changes
csvFile = 'C:\Users\John Arenas\Desktop\data\uns-performance-evaluation\data\raw\collected_metrics_220tags.csv';

%% Configuration

% Metric column names as they appear in the CSV header
metrics = {
    'sessions'
    'subscriptions'
    'messages_inbound'
    'messages_outbound'
    'received_kb'
    'sent_kb'
    'total_kb'
};

% Y-axis labels for each metric
labely = {
    'Sessions [u]'
    'Subscriptions [u]'
    'Messages Inbound [messages]'
    'Messages Outbound [messages]'
    'Received Packets [KB]'
    'Sent Packets [KB]'
    'Total Packets [KB]'
};

% Plot color (matches EMQX Cloud dashboard palette)
lineColor = [0.18, 0.62, 0.95];   % blue

%% Load CSV
T = readtable(csvFile, 'PreserveVariableNames', true);

% Parse timestamp column
if ~isdatetime(T.timestamp)
    try
        T.timestamp = datetime(T.timestamp, 'InputFormat', 'yyyy-MM-dd HH:mm:ss');
    catch
        T.timestamp = datetime(T.timestamp, 'ConvertFrom', 'excel');
    end
end

fprintf('Loaded %d samples from:\n  %s\n\n', height(T), csvFile);

%% Plot loop – one figure per metric
for i = 1:numel(metrics)

    colName = metrics{i};
    values  = T{:, colName};

    % Replace NaN with 0
    values(isnan(values)) = 0;

    % Zero-pad boundaries so curves start and end at baseline
    t_plot = [T.timestamp(1);   T.timestamp;   T.timestamp(end)];
    v_plot = [0;                values;         0               ];

    fprintf('Metric %d/%d: %-25s | mean = %.4f | max = %.4f\n', ...
        i, numel(metrics), colName, mean(values), max(values));

    % --- Build figure ---
    figure('Name', colName, 'NumberTitle', 'off');

    area(t_plot, v_plot, ...
        'FaceColor', lineColor, ...
        'FaceAlpha', 0.25, ...
        'EdgeColor', lineColor, ...
        'LineWidth', 1.6);

    % Grid styling
    grid on;
    grid minor;
    ax = gca;
    ax.GridAlpha      = 0.30;
    ax.MinorGridAlpha = 0.15;

    % Axis labels
    xlabel('Time');
    ylabel(labely{i});

    % Y-axis upper limit: 10% headroom above maximum
    ymax = max(v_plot);
    if ymax > 0
        ylim([0, ymax * 1.1]);
    else
        ylim([0, 1]);
    end

    % Format X-axis ticks as HH:MM
    ax.XAxis.TickLabelFormat = 'HH:mm';

end

fprintf('\nAll %d figures generated.\n', numel(metrics));
